import type { NextFunction, Request, Response } from 'express';
import { logger } from '../utils/logger';
import { signToken, verifyToken } from '../utils/auth';

export function loginHandler(req: Request, res: Response) {
  const { email, password } = req.body ?? {};

  if (!email || !password) {
    return res.status(400).json({ error: 'email and password are required' });
  }

  const token = signToken({ sub: 'u1', email });
  return res.status(200).json({ token });
}

export function authMiddleware(req: Request, res: Response, next: NextFunction) {
  const raw = req.headers.authorization;
  const token = raw?.startsWith('Bearer ') ? raw.slice(7) : undefined;

  if (!token) {
    return res.status(401).json({ error: 'missing bearer token' });
  }

  try {
    const payload = verifyToken(token);
    (req as Request & { auth?: unknown }).auth = payload;
    return next();
  } catch (error) {
    logger.error('invalid token', error);
    return res.status(401).json({ error: 'invalid token' });
  }
}

import type { ReactNode } from 'react';

type AuthGuardProps = {
  isAuthenticated: boolean;
  fallback?: ReactNode;
  children: ReactNode;
};

export function AuthGuard({ isAuthenticated, fallback = null, children }: AuthGuardProps) {
  if (!isAuthenticated) {
    return <>{fallback}</>;
  }

  return <>{children}</>;
}

