import { describe, expect, it } from 'vitest';
import { signToken, verifyToken } from '../../src/utils/auth';

describe('auth utils', () => {
  it('signs and verifies a token', () => {
    const token = signToken({ sub: 'u1', email: 'dev@example.com' });
    const payload = verifyToken(token);

    expect(payload.sub).toBe('u1');
    expect(payload.email).toBe('dev@example.com');
  });

  it('throws for malformed token', () => {
    expect(() => verifyToken('bad.token')).toThrow();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { Request, Response } from 'express';
import { authMiddleware, loginHandler } from '../../src/api/auth';

function mockRes() {
  const res = {
    status: vi.fn().mockReturnThis(),
    json: vi.fn().mockReturnThis()
  } as unknown as Response;
  return res;
}

describe('loginHandler', () => {
  it('returns token for valid credentials shape', () => {
    const req = { body: { email: 'dev@example.com', password: 'pw' } } as Request;
    const res = mockRes();

    loginHandler(req, res);

    expect(res.status).toHaveBeenCalledWith(200);
    expect(res.json).toHaveBeenCalledWith(expect.objectContaining({ token: expect.any(String) }));
  });

  it('returns 400 when missing credentials', () => {
    const req = { body: {} } as Request;
    const res = mockRes();

    loginHandler(req, res);

    expect(res.status).toHaveBeenCalledWith(400);
  });
});

describe('authMiddleware', () => {
  it('returns 401 when auth header missing', () => {
    const req = { headers: {} } as Request;
    const res = mockRes();
    const next = vi.fn();

    authMiddleware(req, res, next);

    expect(res.status).toHaveBeenCalledWith(401);
    expect(next).not.toHaveBeenCalled();
  });

  it('calls next when token is valid', () => {
    const loginReq = { body: { email: 'dev@example.com', password: 'pw' } } as Request;
    const loginRes = mockRes();
    loginHandler(loginReq, loginRes);
    const token = (loginRes.json as unknown as { mock: { calls: Array<Array<{ token: string }>> } }).mock.calls[0][0].token;

    const req = { headers: { authorization: `Bearer ${token}` } } as unknown as Request;
    const res = mockRes();
    const next = vi.fn();

    authMiddleware(req, res, next);

    expect(next).toHaveBeenCalledTimes(1);
  });
});
